sql:
SELECT rental_id, date, bike_id, season
FROM rentals
WHERE rental_type = 'single' AND total_duration_minutes < 60;

SELECT rental_id, date, hour, rented_bike_count
FROM rentals
WHERE rental_id = 1;

SELECT AVG(rentals.total_duration_minutes) AS Average_Duration
FROM rentals
JOIN holiday_rentals ON rentals.rental_id = holiday_rentals.rental_id;

SELECT AVG(distance_traveled_km) AS avg_distance
FROM rentals
WHERE holiday = 1;

SELECT holiday_id, COUNT(*) AS rental_count
FROM holiday_rentals
GROUP BY holiday_id;

SELECT season, AVG(distance_traveled_km) AS avg_distance
FROM rentals
GROUP BY season;

external_knowledge:
- 'round trip' in rental types refers to trips where the rental includes both going and coming back;
- 'positive' in weather effect suggests favorable weather conditions for rentals;
- 'season_id = 0' likely indicates a specific season of interest (this may vary based on the context, for example, it could be winter);
- 'holiday_id = 1' symbolizes a specific holiday (this is context-dependent and may represent a unique holiday in the database).

'special days' refers to holidays;
the rental identifier uniquely identifies each rental;
the holiday name specifies the particular holiday;
the date field denotes the rental date that coincides with a holiday.
